b'import pytest\nimport sys\nfrom cli import main\n\ndef test_celsius_to_fahrenheit(monkeypatch):\n    monkeypatch.setattr(sys, "argv", ["script.py", "--temperature", "25", "--from", "celsius", "--to", "fahrenheit"])\n    with pytest.capture_output() as cap:\n        main()\n    assert cap.stdout == "25 celsius is equal to 77.0 fahrenheit.\\n"\n\ndef test_fahrenheit_to_celsius(monkeypatch):\n    monkeypatch.setattr(sys, "argv", ["script.py", "--temperature", "77", "--from", "fahrenheit", "--to", "celsius"])\n    with pytest.capture_output() as cap:\n        main()\n    assert cap.stdout == "77 fahrenheit is equal to 25.0 celsius.\\n"\n\ndef test_celsius_to_kelvin(monkeypatch):\n    monkeypatch.setattr(sys, "argv", ["script.py", "--temperature", "0", "--from", "celsius", "--to", "kelvin"])\n    with pytest.capture_output() as cap:\n        main()\n    assert cap.stdout == "0 celsius is equal to 273.15 kelvin.\\n"\n\ndef test_unsupported_conversion(monkeypatch):\n    monkeypatch.setattr(sys, "argv", ["script.py", "--temperature", "100", "--from", "fahrenheit", "--to", "kelvin"])\n    with pytest.raises(SystemExit) as excinfo:\n        main()\n    assert "Conversion from fahrenheit to kelvin is not supported" in str(excinfo.value)\n\ndef test_missing_temperature(monkeypatch):\n    monkeypatch.setattr(sys, "argv", ["script.py", "--from", "celsius", "--to", "fahrenheit"])\n    with pytest.raises(SystemExit) as excinfo:\n        main()\n    assert "the following arguments are required: temperature" in str(excinfo.value)\n\ndef test_missing_from(monkeypatch):\n    monkeypatch.setattr(sys, "argv", ["script.py", "--temperature", "100", "--to", "fahrenheit"])\n    with pytest.raises(SystemExit) as excinfo:\n        main()\n    assert "the following arguments are required: --from" in str(excinfo.value)\n\ndef test_missing_to(monkeypatch):\n    monkeypatch.setattr(sys, "argv", ["script.py", "--temperature", "100", "--from", "celsius"])\n    with pytest.raises(SystemExit) as excinfo:\n        main()\n    assert "the following arguments are required: --to" in str(excinfo.value)\n\ndef test_invalid_from_unit(monkeypatch):\n    monkeypatch.setattr(sys, "argv", ["script.py", "--temperature", "100", "--from", "invalid", "--to", "fahrenheit"])\n    with pytest.raises(SystemExit) as excinfo:\n        main()\n    assert "invalid choice: invalid (choose from celsius, fahrenheit, kelvin)" in str(excinfo.value)\n\ndef test_invalid_to_unit(monkeypatch):\n    monkeypatch.setattr(sys, "argv", ["script.py", "--temperature", "100", "--from", "celsius", "--to", "invalid"])\n    with pytest.raises(SystemExit) as excinfo:\n        main()\n    assert "invalid choice: invalid (choose from celsius, fahrenheit, kelvin)" in str(excinfo.value)'